// Normalises the incoming payload and validates the minimum required fields.
// Sets is_valid_request = true only when matter_id and a valid trigger_date are present.

const raw  = $input.first().json;
const body = raw.body || raw;

const matterId         = String(body.matter_id || '').trim();
const clioMatterId     = body.clio_matter_id  != null ? body.clio_matter_id : null;
const triggerDate      = String(body.trigger_date || '').trim();
const matterTitle      = String(body.matter_title || body.case_title || 'Matter').trim();
const attorneyEmail    = String(body.attorney_email || '').trim();
const calendarPlatform = String(body.calendar_platform || 'google').toLowerCase().trim();
const rules            = Array.isArray(body.rules) ? body.rules : [];

const dateOk =
  /^\d{4}-\d{2}-\d{2}$/.test(triggerDate) &&
  !isNaN(new Date(triggerDate + 'T12:00:00Z').getTime());

const isValidRequest = !!matterId && dateOk;

return [{ json: {
  matter_id:         matterId,
  clio_matter_id:    clioMatterId,
  trigger_date:      triggerDate,
  matter_title:      matterTitle,
  attorney_email:    attorneyEmail,
  calendar_platform: calendarPlatform,
  rules,
  is_valid_request:  isValidRequest,
  validation_error:  !matterId  ? 'Missing matter_id'
                   : !dateOk   ? 'Invalid or missing trigger_date — use YYYY-MM-DD'
                   : null,
  received_at: new Date().toISOString(),
}}];

// Reads firm details from n8n Variables (project → Variables tab).
// Set: FIRM_NAME, FIRM_EMAIL, FIRM_TIMEZONE, OPS1_SHEET_ID
const FIRM_NAME  = $vars.FIRM_NAME;
const FIRM_EMAIL = $vars.FIRM_EMAIL;
const TIMEZONE   = $vars.FIRM_TIMEZONE;   // e.g. 'America/Chicago', 'America/Los_Angeles'
const SHEET_ID   = $vars.OPS1_SHEET_ID;   // same OPS1 Compliance Log sheet used by the Bar-Compliance Guardrail

// ⚙️ Replace these example placeholders with the actual rules your attorney has entered.
// This workflow never suggests or interprets legal deadlines — the firm owns every rule.
//
// offset_days: positive = after trigger date, negative = before trigger date
// offset_type: 'business' = skip weekends + US federal holidays
//              'calendar' = count every day including weekends and holidays
const DEFAULT_RULES = [
  {
    name:        'Example Deadline A — replace this',
    offset_days: 30,
    offset_type: 'business',
    description: 'Placeholder — replace with your firm rule (e.g. 30 business days from trigger date per local rules)',
  },
  {
    name:        'Example Deadline B — replace this',
    offset_days: 60,
    offset_type: 'business',
    description: 'Placeholder — replace with your firm rule (e.g. 60 business days from trigger date per local rules)',
  },
  {
    name:        'Example Deadline C — replace this',
    offset_days: 14,
    offset_type: 'calendar',
    description: 'Placeholder — replace with your firm rule (e.g. 14 calendar days from trigger date per local rules)',
  },
];

// ── US Federal Holiday calculator ─────────────────────────────────────────────
function nthWeekday(year, month0, weekday, n) {
  if (n > 0) {
    const d = new Date(Date.UTC(year, month0, 1));
    let count = 0;
    while (true) {
      if (d.getUTCDay() === weekday) { count++; if (count === n) return new Date(d); }
      d.setUTCDate(d.getUTCDate() + 1);
    }
  } else {
    const d = new Date(Date.UTC(year, month0 + 1, 0));
    while (true) {
      if (d.getUTCDay() === weekday) return new Date(d);
      d.setUTCDate(d.getUTCDate() - 1);
    }
  }
}

function getUSFederalHolidays(year) {
  const set = new Set();
  function addObserved(date) {
    const d = new Date(date);
    const day = d.getUTCDay();
    if (day === 6) d.setUTCDate(d.getUTCDate() - 1); // Saturday → observe Friday
    if (day === 0) d.setUTCDate(d.getUTCDate() + 1); // Sunday → observe Monday
    set.add(d.toISOString().slice(0, 10));
  }
  addObserved(new Date(Date.UTC(year, 0, 1)));     // New Year's Day
  addObserved(nthWeekday(year, 0, 1, 3));           // MLK Day (3rd Mon Jan)
  addObserved(nthWeekday(year, 1, 1, 3));           // Presidents' Day (3rd Mon Feb)
  addObserved(nthWeekday(year, 4, 1, -1));          // Memorial Day (last Mon May)
  addObserved(new Date(Date.UTC(year, 5, 19)));     // Juneteenth
  addObserved(new Date(Date.UTC(year, 6, 4)));      // Independence Day
  addObserved(nthWeekday(year, 8, 1, 1));           // Labor Day (1st Mon Sep)
  addObserved(nthWeekday(year, 9, 1, 2));           // Columbus Day (2nd Mon Oct)
  addObserved(new Date(Date.UTC(year, 10, 11)));    // Veterans Day
  addObserved(nthWeekday(year, 10, 4, 4));          // Thanksgiving (4th Thu Nov)
  addObserved(new Date(Date.UTC(year, 11, 25)));    // Christmas
  return set;
}

const holidayCache = {};

function isBusinessDay(dateStr) {
  const d = new Date(dateStr + 'T12:00:00Z');
  const dow = d.getUTCDay();
  if (dow === 0 || dow === 6) return false;
  const yr = d.getUTCFullYear();
  if (!holidayCache[yr]) holidayCache[yr] = getUSFederalHolidays(yr);
  return !holidayCache[yr].has(dateStr);
}

function addBusinessDays(startDateStr, n) {
  const direction = n >= 0 ? 1 : -1;
  const steps = Math.abs(n);
  const d = new Date(startDateStr + 'T12:00:00Z');
  let counted = 0;
  while (counted < steps) {
    d.setUTCDate(d.getUTCDate() + direction);
    if (isBusinessDay(d.toISOString().slice(0, 10))) counted++;
  }
  return d.toISOString().slice(0, 10);
}

function addCalendarDays(startDateStr, n) {
  const d = new Date(startDateStr + 'T12:00:00Z');
  d.setUTCDate(d.getUTCDate() + n);
  return d.toISOString().slice(0, 10);
}

// ── Main ──────────────────────────────────────────────────────────────────────
const item  = $input.first().json;
const rules = (item.rules && item.rules.length > 0) ? item.rules : DEFAULT_RULES;

const deadlines = rules.map(rule => {
  const offsetDays = Number(rule.offset_days) || 0;
  const offsetType = (rule.offset_type || 'business').toLowerCase();
  const deadlineDate = offsetType === 'calendar'
    ? addCalendarDays(item.trigger_date, offsetDays)
    : addBusinessDays(item.trigger_date, offsetDays);

  return {
    matter_id:         item.matter_id,
    clio_matter_id:    item.clio_matter_id,
    matter_title:      item.matter_title,
    attorney_email:    item.attorney_email,
    calendar_platform: item.calendar_platform,
    rule_name:         rule.name,
    deadline_date:     deadlineDate,
    trigger_date:      item.trigger_date,
    offset_days:       offsetDays,
    offset_type:       offsetType,
    description:       rule.description || rule.name,
    firm_name:         FIRM_NAME,
    firm_email:        FIRM_EMAIL,
    timezone:          TIMEZONE,
    sheet_id:          SHEET_ID,
  };
});

return deadlines.map(d => ({ json: d }));
